const ctx = $json; // resposta do contexto

const business = ctx;
const ideationForm = ctx.latest_form_responses?.ideation_form_response || null;

if (!ideationForm) {
  throw new Error('Nenhum FormResponse de ideação encontrado para este negócio.');
}

const ideationData = ideationForm.data;

// Aqui você pode montar um prompt baseado no "01_Prompt_Diagnóstico.docx".
// Vou montar um esqueleto simplificado; depois você refina o texto.

const prompt = `
Você é um consultor de negócios da plataforma Guia Norte, especializado em pequenos comércios e serviços.

Contexto do negócio:
- Nome do negócio: ${business.name || 'não informado'}
- Segmento: ${business.segment || 'não informado'}
- Tipo: ${business.business_type || 'não informado'}
- Cidade/UF: ${business.city || ''} / ${business.state || ''}

Dados do formulário de Ideação (JSON):
${JSON.stringify(ideationData, null, 2)}

Tarefa:
1. Faça um resumo amigável da ideia (2–3 frases).
2. Analise a maturidade da ideia e classifique como uma destas opções:
   - "Ideia ainda muito crua"
   - "Ideia em desenvolvimento"
   - "Ideia bem estruturada, pronta para planejar"
3. Aponte 4–6 pontos cegos ou riscos.
4. Sugira 3–5 próximos passos práticos antes de ir para o Plano de Negócios.

Responda em português, em formato de texto organizado com títulos e listas.
`;

return [{
  json: {
    business_id: business.id,
    form_response_id: ideationForm.id,
    prompt,
  },
}];

const aiOutput = $json; // Saída do node AI Agent

// O campo 'output' do AI Agent contém o texto do diagnóstico
const diagnosisContent = aiOutput.output;

// O raw_response deve ser o JSON completo que o AI Agent retornou
// Isso garante que ele seja um objeto JSON válido
const rawResponseData = aiOutput;

// Pegamos os dados que vieram dos nodes anteriores (Webhook, Contexto, Prompt)
// e que foram passados adiante pelo AI Agent (se configurado para isso)
const businessId = aiOutput.business_id;
const formResponseId = aiOutput.form_response_id;

// Monta o objeto final para o POST no Django
return [{
  json: {
    business_id: businessId,
    form_response_id: formResponseId,
    diagnosis_type: "ideation", // Ou {{ $json.diagnosis_type }} se vier de um node anterior
    diagnosis_version: "1.0",
    status: "done",
    content: diagnosisContent, // Texto do diagnóstico
    raw_response: rawResponseData, // Objeto JSON completo da resposta da IA
    is_free: true,
    model_name: "groq-agent" // Nome do modelo que você usou (Groq)
  }
}];
